VALUES
  ('cpa-moex-00111', 'cpa', 'cpa-moex-113-9023a44f', 'sub-cpa-02', NULL, 'single_choice', 'A股份有限公司（下稱A公司）的前二大股東為B股份有限公司（下稱B公司）與C股份有限 公司（下稱C公司），其分別持有A公司已發行股份總數9%與8%的股份。此外B公司與C公司 的已發行股份全數為D股份有限公司（下稱D公司）持有。A公司應向中央主管機關建置或指定 之資訊平臺申報以下何人的姓名或名稱及其持股數？', '["B公司", "D公司", "持有D公司股份51%的自然人甲", "A公司的經理人乙"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:59+00:00", "source_pdf_sha1": "de36fb7a9031", "answer_pdf_sha1": "369b73c92d99", "source_family": "moex-gov-tw", "moex": {"exam_code": "113130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "113", "exam_name": "113年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00112', 'cpa', 'cpa-moex-113-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '非屬公營事業之股份有限公司發行新股，下列敘述，何者正確？', '["股東之新股認購權，不得與原有股份分離而獨立轉讓", "公司發行特別股時，員工無優先認購權", "公司發行新股應保留一定比例予員工認購，但經目的事業主管機關專案核定者，不在此限", "特別股股東於公司發行新股時，無股東優先認購權"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:59+00:00", "source_pdf_sha1": "de36fb7a9031", "answer_pdf_sha1": "369b73c92d99", "source_family": "moex-gov-tw", "moex": {"exam_code": "113130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "113", "exam_name": "113年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00113', 'cpa', 'cpa-moex-113-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '某公司為小規模之公司，負責人無暇親自辦理公司登記，欲委任代理人為之。依公司法規定，下 列何者得為代理人？', '["律師、代書", "代書、記帳士", "記帳士、會計師", "律師、會計師"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:59+00:00", "source_pdf_sha1": "de36fb7a9031", "answer_pdf_sha1": "369b73c92d99", "source_family": "moex-gov-tw", "moex": {"exam_code": "113130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "113", "exam_name": "113年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00114', 'cpa', 'cpa-moex-113-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '非公開發行之A股份有限公司（下稱A公司），董事會委任董事長甲之長子乙為總經理、次女丙 為財務經理，A公司在甲之家族把持下，經營狀況不斷惡化。今年股東會中，小股東提臨時動議 改選總經理，並作成決議選任與甲之家族無關之丁擔任總經理。此一總經理改選案效力如何？', '["有效", "得撤銷", "無效", "須經原總經理承認始生效力"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:59+00:00", "source_pdf_sha1": "de36fb7a9031", "answer_pdf_sha1": "369b73c92d99", "source_family": "moex-gov-tw", "moex": {"exam_code": "113130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "113", "exam_name": "113年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00115', 'cpa', 'cpa-moex-113-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '股份有限公司股票之發行，下列敘述，何者正確？', '["非公開發行股票公司實收資本額達5億元以上者，應發行股票", "公開發行股票公司有發行股票之義務", "有發行股票義務之公司應在設立登記或發行新股變更登記後6個月內發行股票", "無發行股票義務之公司，其股票之發行應經主管機關核准後，始得為之"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:59+00:00", "source_pdf_sha1": "de36fb7a9031", "answer_pdf_sha1": "369b73c92d99", "source_family": "moex-gov-tw", "moex": {"exam_code": "113130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "113", "exam_name": "113年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00116', 'cpa', 'cpa-moex-113-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '甲為A食品股份有限公司（下稱A公司）之董事，經好友乙的請託擔任B食品股份有限公司（下 稱B公司）之董事，甲與A公司、B公司以下的何種作為符合公司法的規定？', '["甲僅需取得股東會之許可，無須向股東說明擔任B公司行為之重要內容", "A公司股東會為許可甲兼職之決議，應有代表已發行股份總數二分之一以上股東之出席，以出 席股東表決權過半數之同意行之", "若甲未取得股東會同意便出任B公司董事，A公司股東會得由代表已發行股份總數二分之一以 上股東之出席，以出席股東表決權過半數之同意行之決議，將甲擔任B公司董事之所得視為A 公司之所得", "前項經A公司股東會決議請求歸入甲兼職之所得限於決議前二年之所得"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:59+00:00", "source_pdf_sha1": "de36fb7a9031", "answer_pdf_sha1": "369b73c92d99", "source_family": "moex-gov-tw", "moex": {"exam_code": "113130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "113", "exam_name": "113年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00117', 'cpa', 'cpa-moex-113-9023a44f', 'sub-cpa-02', NULL, 'single_choice', 'A公司係依我國公司法組織、登記、成立之股份有限公司，業務遍及全世界。為便於國內外客戶 辨識公司之同一性，除登記中文公司名稱外，亦考慮登記英文公司名稱。依現行公司法關於公司 外文名稱之規定，下列敘述，何者正確？', '["A公司申請英文名稱登記前，仍應向經濟部申請預查並取得核准", "A公司之英文名稱於完成登記前，不得對外使用該英文名稱", "欲申請英文名稱登記，A公司應於章程中記載公司英文名稱", "A 公司英文名稱登記後，如該名稱與公益團體之英文名稱相同，經濟部得逕予廢止 A 公司英 文名稱之登記"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:59+00:00", "source_pdf_sha1": "de36fb7a9031", "answer_pdf_sha1": "369b73c92d99", "source_family": "moex-gov-tw", "moex": {"exam_code": "113130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "113", "exam_name": "113年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00118', 'cpa', 'cpa-moex-113-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '投資人甲透過A證券經紀商下單，希望買入B上市公司之股票，經臺灣證券交易所撮合後，與投 資人乙委託C證券經紀商下單賣出之賣單成交。下列敘述，何者正確？', '["股票交易之買賣契約成立於A與C之間", "股票交易之買賣契約成立於甲與乙之間", "股票交易之買賣契約成立於甲與C之間", "股票交易之買賣契約成立於乙與A之間"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:59+00:00", "source_pdf_sha1": "de36fb7a9031", "answer_pdf_sha1": "369b73c92d99", "source_family": "moex-gov-tw", "moex": {"exam_code": "113130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "113", "exam_name": "113年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00119', 'cpa', 'cpa-moex-113-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '關於證券交易法之私募規定，下列敘述，何者錯誤？', '["私募股票購買人的子女，得因繼承取得該股票", "私募之應募人得自有價證券交付日起滿3年後自由轉讓", "公司債私募之應募人或購買人倘違反轉售之限制，僅須受行政罰", "關於私募股票之轉售限制，應於股票上以明顯文字註記，並於交付應募人或購買人之相關書面 文件中載明"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:59+00:00", "source_pdf_sha1": "de36fb7a9031", "answer_pdf_sha1": "369b73c92d99", "source_family": "moex-gov-tw", "moex": {"exam_code": "113130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "113", "exam_name": "113年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00120', 'cpa', 'cpa-moex-113-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '證券交易法有關私募有價證券之規定，下列敘述，何者正確？', '["公開發行股票公司私募普通公司債，須經股東會特別決議始得為之", "公開發行股票公司私募新股，僅須董事會特別決議即可", "公開發行股票公司私募普通公司債之總額，不得逾全部資產減去全部負債餘額之百分之四百", "公開發行股票公司私募有價證券，應募人只要符合證券交易法之資格，其人數並無限制"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:59+00:00", "source_pdf_sha1": "de36fb7a9031", "answer_pdf_sha1": "369b73c92d99", "source_family": "moex-gov-tw", "moex": {"exam_code": "113130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "113", "exam_name": "113年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL)
